    tokens = text.lower().split()
    # Remove stop words
    stop_words = set(["the", "and", "or", "a", "an", "in", "on", "to", "of", "is", "it", "this", "that"])
    filtered_tokens = [word for word in tokens if word not in stop_words]
    # Stemming
    stemmed_tokens = [word.stem() for word in filtered_tokens]
    return stemmed_tokens

